import sailpoint.object.*;
import sailpoint.transformer.*;

HashMap formModel=new HashMap();	
formModel.put("transformerClass","sailpoint.transformer.IdentityTransformer");		
IdentityTransformer transformer = new IdentityTransformer(context);

formModel.put(IdentityTransformer.ATTR_TRANSFORMER_CLASS, transformer.getClass().getName());
formModel.put(IdentityTransformer.ATTR_TRANSFORMER_OPTIONS, "sailpoint.transformer.IdentityTransformerOptions");
formModel.put(IdentityTransformer.OP_IDENTITY_EXPAND, Boolean.FALSE);
formModel.put(IdentityTransformer.OPT_LINK_EXPAND, Boolean.FALSE);

System.out.println("formModel"+formModel);
return formModel;

import sailpoint.object.*;
Identity id = null;
if(null != identityName) {
id = context.getObjectByName(Identity.class, identityName);
return id.getDisplayName();
}

import sailpoint.object.Identity;;

Identity identity = context.getObjectByName(Identity.class, identityName);
identity.setPassword("TermUser@123");
context.saveObject(identity);
context.commitTransaction();
